	apiURL := BaseURL + "/1/clouddrive/file/sort"
	query := url.Values{}
	query.Set("pdir_fid", parentID)
	query.Set("_page", "1")
	query.Set("_size", "100")
	query.Set("_sort", "file_type:asc,updated_at:desc")

	resp, err := q.doRequest(ctx, "GET", apiURL, query, nil, false)
	if err != nil {
		return nil, err
	}

	var res struct {
		Code interface{} `json:"code"`
		Data struct {
			List []struct {
				Fid      string `json:"fid"`
