	}

	codeStr := fmt.Sprintf("%v", res.Code)
	if codeStr != "0" && codeStr != "0.0" {
		return nil, fmt.Errorf("Quark API error: %v", res.Code)
	}

	var files []core.FileInfo
	for _, item := range res.Data.List {
		files = append(files, core.FileInfo{
			ID:        item.Fid,
			Name:      item.FileName,
			IsFolder:  item.Dir,
			Size:      item.Size,
