	// 如果有 kps，优先调用 App 接口获取 (能识别 88VIP 等细分等级)
	vipFetched := false
	if q.mparam["kps"] != "" {
		queryGrowth := url.Values{}
		growthResp, err := q.doRequest(ctx, "GET", BaseURLApp+"/1/clouddrive/capacity/growth/info", queryGrowth, nil, true)
